var e=[{id:`L5_1`,type:`dialog`,speaker:null,text:{KOREA:`저, 저게 뭐야! 괴물이다!`,JPN:`あ、あれは何だ？　怪物だ！`,ENG:`W-what the heck is that? It's a monster!`,TWN:`那、那是什麼啊！怪物啊！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:null,R:null}}},{id:`L6_1`,type:`dialog`,speaker:null,text:{KOREA:`도시 한복판에 어째서 저런 게 나타난 거지?!`,JPN:`都会のど真ん中に、なぜあんなものが現れるんだ！？`,ENG:`How did that thing make it all the way into the center of the city?`,TWN:`市中心怎麼會有那種東西啊？！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:null,R:null}}},{id:`L7_1`,type:`dialog`,speaker:null,text:{KOREA:`태스크포스를 불러! 대체 어디에 있는 거야?!`,JPN:`タスクフォースカンパニーを呼べ！　いったいどこにいるんだ！？`,ENG:`Call the TASKFORCE company! Where the heck are they?`,TWN:`快去叫特遣勢力！到底在哪裡啊？！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:null,R:null}}},{id:`L8_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`여러분! 당황하지 말고 물러서세요!`,JPN:`皆さん！　慌てないで下がってください！`,ENG:`Everyone! Please stay calm and do not panic!`,TWN:`各位！請不要驚慌，退後！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:null,text:{KOREA:`다, 당신은 누구요?!`,JPN:`あ、あなたは誰ですか？`,ENG:`W-who are you?`,TWN:`妳、妳是誰？！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`경찰입니다! 저 괴물은 제가 처치할 테니 다들 안심하세요!`,JPN:`警察です！　あの怪物は私が始末しますから、安心してください！`,ENG:`I'm with the police. Stay calm. I'll take care of that thing!`,TWN:`我是警察！我會處置那個怪物的，請各位放心吧！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`여기는 이유미 경정!`,JPN:`こちらカスカベ警視！`,ENG:`This is Major Lee Yumi.`,TWN:`這裡是李悠美警正！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L13_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`추적중인 범죄자가 시내 방향으로 진입을 시도한다! 내가 처치하겠다!`,JPN:`追跡中の犯罪者が市内に侵入しようとしている！
私が始末する！`,ENG:`The suspect on the loose is attempting entry into downtown. I'll put her down!`,TWN:`追捕中的罪犯試圖進入市區！我來處置她！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L16_1`,type:`dialog`,speaker:`RADIO_EXTRA_POLICE_NULL`,text:{KOREA:`네? 처치요?`,JPN:`はい？　始末ですか？`,ENG:`Huh? Put her down?`,TWN:`咦？處置？`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L17_1`,type:`dialog`,speaker:`RADIO_EXTRA_POLICE_NULL`,text:{KOREA:`무슨 소립니까? 아직 사살명령 같은 건 안 나왔는데......`,JPN:`どういうことです？　まだ射殺命令は出ていないのに……`,ENG:`What are you talking about? Use of lethal force hasn't been authorized yet!`,TWN:`妳在說什麼？現在還沒有下達射殺命令之類的……`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`......`,JPN:`……`,ENG:`......`,TWN:`……`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`겨, 경찰 언니...... 살려주세요...... 잘못했어요!!`,JPN:`け、警察のお姉さん……助けてください……
反省しますから！！`,ENG:`P-please! Please don't kill me... It won't happen again!`,TWN:`警、警察姐姐……救救我吧……我錯了！！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L23_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`시, 시끄러워!`,JPN:`う、うるさい！`,ENG:`Sh-shut up!`,TWN:`吵、吵死了！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L24_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`그럼 처음부터 그런 약은 손을 안 댔어야지!`,JPN:`だったら最初からそんな薬物に手を出さなければよかったじゃない！`,ENG:`You shouldn't have resorted to that drug in the first place!`,TWN:`那妳從一開始就不該碰這種藥！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`YUMI_POLICE_NULL_NULL`,text:{KOREA:`어쨌든 넌 오늘 여기서 끝이야!`,JPN:`とにかく、あなたは今日ここで終わりだから！`,ENG:`This is your end, here and now.`,TWN:`無論如何，今天就是妳的死期了！`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L27_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`하, 하지만...... 그게 있으면......`,JPN:`で、でも……あれさえあれば……`,ENG:`But... I just...`,TWN:`可、可是……有那個的話……`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L28_1`,type:`dialog`,speaker:`GIRLSTUDENT_EXTRA_NULL_NULL`,text:{KOREA:`오빠가 살아 돌아올 가능성이 높다고 해서......`,JPN:`お兄ちゃんが生きて帰ってこられると聞いて……`,ENG:`I was told that it'd help my brother return home safely...`,TWN:`哥哥活過來的可能性就很高……`},stage:{bg:`HIGHWAY_RAINY`,slots:{L:null,C:{char_id:`YUMI_POLICE_NULL_NULL`,face:`UNIT_IDLE`},R:null}}}];export{e as default};